#ifndef DISK_H
#define DISK_H

/*
 * disk.h - Disk I/O utilities for binary files with block-level access.
 *
 * Provides a thin abstraction over stdio so that the algorithms can read
 * and write arrays stored on disk using whole blocks of BLOCK_SIZE bytes.
 * Each open file keeps a single block-sized buffer in main memory that
 * caches the most recently referenced block. Every time the cache is
 * filled from the file we count one disk read, and every time it is
 * flushed back we count one disk write.
 */

#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <string.h>

#define BLOCK_SIZE       4096            /* B = 4096 bytes                            */
#define INT64_SIZE       8               /* sizeof(int64_t)                           */
#define INTS_PER_BLOCK   (BLOCK_SIZE / INT64_SIZE)  /* 512 ints per block  */

/* DiskFile: open binary file together with a one-block buffer cache.
 *   fp            - stdio FILE* for the underlying binary file
 *   buffer        - BLOCK_SIZE byte cache for the most recently
 *                   referenced block
 *   dirty         - 1 if buffer holds modified data that has not yet
 *                   been written to disk
 *   block_num     - index (in blocks) of the block currently in buffer;
 *                   -1 means the buffer is empty
 *   total_blocks  - number of valid blocks the file currently holds
 *   is_open       - 1 while the file handle is valid
 */
typedef struct {
    FILE*  fp;
    char*  buffer;
    int    dirty;
    long   block_num;
    long   total_blocks;
    int    is_open;
} DiskFile;

/* Counters that track the number of disk reads and writes issued since
 * the last call to reset_counters(). They are defined in disk.c. */
extern long g_disk_reads;
extern long g_disk_writes;

/* Open the binary file whose path is `filename`. `mode` follows the
 * fopen() conventions: "rb" for reading, "wb" for writing (truncate),
 * "rb+" for read/write. Returns NULL on failure. */
DiskFile* disk_open(const char* filename, const char* mode);

/* Flush the cached block if it is dirty and close the file. Safe to call
 * with a NULL pointer. */
void disk_close(DiskFile* df);

/* Read block `block_num` (in blocks, not bytes) of `df` into `buf`,
 * which must point to at least BLOCK_SIZE bytes. If the requested block
 * is already cached the call does not touch disk. Increments the read
 * counter otherwise. Reading beyond the end of the file fills `buf`
 * with INT64_MAX sentinel values so that merge algorithms can keep
 * working past the last valid element. */
void disk_read_block(DiskFile* df, long block_num, void* buf);

/* Write `buf` (BLOCK_SIZE bytes) into block `block_num` of `df`. The
 * write goes into the buffer cache; it is only flushed to disk when the
 * cache is reused or the file is closed. Extends the file if
 * `block_num` is past the current end. Increments the write counter
 * when the block is actually flushed. */
void disk_write_block(DiskFile* df, long block_num, const void* buf);

/* Number of valid blocks currently stored in the file. */
long disk_total_blocks(DiskFile* df);

/* Override the number of valid blocks. Useful after truncating a file. */
void disk_set_total_blocks(DiskFile* df, long total_blocks);

/* Reset both global disk-access counters to zero. */
void reset_counters(void);

/* Total number of disk accesses (reads + writes) since the last reset. */
long total_disk_accesses(void);

#endif /* DISK_H */

#include "disk.h"

/* Global counters tracking the number of physical block transfers. */
long g_disk_reads  = 0;
long g_disk_writes = 0;

/* Open `filename` with the given fopen() mode and attach a single
 * block-sized buffer cache. Returns NULL if the file cannot be opened. */
DiskFile* disk_open(const char* filename, const char* mode) {
    FILE* fp = fopen(filename, mode);
    if (!fp) return NULL;

    DiskFile* df = (DiskFile*)malloc(sizeof(DiskFile));
    df->fp           = fp;
    df->buffer       = (char*)malloc(BLOCK_SIZE);
    df->dirty        = 0;
    df->block_num    = -1;
    df->is_open      = 1;

    if (mode[0] == 'r' && mode[1] != '+') {
        /* Reading-only: figure out the file length. */
        fseek(fp, 0, SEEK_END);
        long size = ftell(fp);
        df->total_blocks = size / BLOCK_SIZE;
        /* An incomplete trailing block still counts as a block. */
        if (size % BLOCK_SIZE != 0) df->total_blocks += 1;
    } else {
        df->total_blocks = 0;
    }
    return df;
}

/* Flush dirty cache (if any) and close the file. */
void disk_close(DiskFile* df) {
    if (!df || !df->is_open) return;
    if (df->dirty && df->block_num >= 0) {
        fseek(df->fp, df->block_num * BLOCK_SIZE, SEEK_SET);
        fwrite(df->buffer, BLOCK_SIZE, 1, df->fp);
        g_disk_writes++;
        df->dirty = 0;
    }
    fclose(df->fp);
    free(df->buffer);
    df->is_open = 0;
    free(df);
}

/* Fill `buf` with the contents of block `block_num`. */
void disk_read_block(DiskFile* df, long block_num, void* buf) {
    if (block_num < 0) {
        memset(buf, 0, BLOCK_SIZE);
        return;
    }
    /* Cache hit: avoid disk I/O. */
    if (df->block_num == block_num && !df->dirty) {
        memcpy(buf, df->buffer, BLOCK_SIZE);
        return;
    }
    /* Need to load another block: flush any pending write first. */
    if (df->dirty && df->block_num >= 0) {
        fseek(df->fp, df->block_num * BLOCK_SIZE, SEEK_SET);
        fwrite(df->buffer, BLOCK_SIZE, 1, df->fp);
        g_disk_writes++;
        df->dirty = 0;
    }
    if (block_num < df->total_blocks) {
        fseek(df->fp, block_num * BLOCK_SIZE, SEEK_SET);
        size_t r = fread(df->buffer, BLOCK_SIZE, 1, df->fp);
        if (r == 0) {
            /* Defensive fill: should not happen for in-range blocks. */
            memset(df->buffer, 0, BLOCK_SIZE);
        }
        g_disk_reads++;
    } else {
        /* Past EOF: return INT64_MAX so merge routines treat it as a
         * dummy "infinity" element. */
        int64_t* p = (int64_t*)df->buffer;
        for (int i = 0; i < INTS_PER_BLOCK; i++) p[i] = INT64_MAX;
    }
    df->block_num = block_num;
    memcpy(buf, df->buffer, BLOCK_SIZE);
}

/* Copy `buf` into the cache for block `block_num`. The write is only
 * pushed to disk when the cache is reused. */
void disk_write_block(DiskFile* df, long block_num, const void* buf) {
    /* Flush dirty cache if we are switching to a different block. */
    if (df->dirty && df->block_num >= 0 && df->block_num != block_num) {
        fseek(df->fp, df->block_num * BLOCK_SIZE, SEEK_SET);
        fwrite(df->buffer, BLOCK_SIZE, 1, df->fp);
        g_disk_writes++;
        df->dirty = 0;
    }
    if (df->block_num != block_num) {
        if (block_num < df->total_blocks) {
            /* Bring the existing block in so we can later modify it. */
            fseek(df->fp, block_num * BLOCK_SIZE, SEEK_SET);
            fread(df->buffer, BLOCK_SIZE, 1, df->fp);
            g_disk_reads++;
        } else {
            memset(df->buffer, 0, BLOCK_SIZE);
        }
        df->block_num = block_num;
    }
    memcpy(df->buffer, buf, BLOCK_SIZE);
    df->dirty = 1;
    if (block_num >= df->total_blocks) {
        df->total_blocks = block_num + 1;
    }
}

long disk_total_blocks(DiskFile* df) {
    return df->total_blocks;
}

void disk_set_total_blocks(DiskFile* df, long total_blocks) {
    df->total_blocks = total_blocks;
}

void reset_counters(void) {
    g_disk_reads  = 0;
    g_disk_writes = 0;
}

long total_disk_accesses(void) {
    return g_disk_reads + g_disk_writes;
}

#ifndef UTILS_H
#define UTILS_H

/*
 * utils.h - Miscellaneous helpers used by the experiment.
 */

#include <stdint.h>
#include <stdlib.h>

/* Seed the PRNG. Calling srand()/srandom() in the library is not
 * thread-safe so we provide a wrapper. */
void utils_seed(unsigned int seed);

/* Return a uniformly random 64-bit integer (uniform over [0, 2^63-1]
 * for reproducibility). */
int64_t utils_rand64(void);

/* Generate `n` random 64-bit integers and store them as the contents of
 * the binary file `filename`. The file is overwritten. */
void gen_random_file(const char* filename, long n);

/* Verify that the binary file `filename` containing `n` int64 elements
 * is sorted in non-decreasing order. Prints a short report and returns
 * 1 if sorted, 0 otherwise. */
int verify_sorted(const char* filename, long n);

/* In-memory quicksort on an array of int64 values. Used to sort the
 * contents of a block or to sort the pivot block of external quicksort.
 * `buf` must point to at least `n` elements. */
void isort(int64_t* buf, long n);

/* In-memory quicksort on an array of int64 values. */
void qsort_int64(int64_t* buf, long n);

/* In-place selection of `k` distinct indices from [0, n). Used to
 * sample pivot positions from a block. Fills `out` with the indices.
 * `out` must have room for `k` elements. */
void sample_indices(long n, int k, long* out);

/* Comparator wrapper suitable for qsort(). */
int int64_cmp(const void* a, const void* b);

/* Comparator wrapper for selecting the k-th smallest element (used in
 * the pivot extraction of external quicksort). */
int int64_cmp_ptr(const void* a, const void* b);

#endif /* UTILS_H */

#include "utils.h"
#include "disk.h"
#include <stdio.h>
#include <string.h>
#include <time.h>

/* PRNG state. We use a simple xorshift64* generator which is good
 * enough for non-cryptographic purposes and is fast. */
static uint64_t rng_state = 0x9E3779B97F4A7C15ULL;

void utils_seed(unsigned int seed) {
    /* Mix the seed into the state using splitmix64. */
    uint64_t z = (uint64_t)seed + 0x9E3779B97F4A7C15ULL;
    z = (z ^ (z >> 30)) * 0xBF58476D1CE4E5B9ULL;
    z = (z ^ (z >> 27)) * 0x94D049BB133111EBULL;
    z = z ^ (z >> 31);
    if (z == 0) z = 1;
    rng_state = z;
}

int64_t utils_rand64(void) {
    uint64_t x = rng_state;
    x ^= x >> 12;
    x ^= x << 25;
    x ^= x >> 27;
    rng_state = x;
    /* Drop the sign bit so values fit in int64_t cleanly. */
    return (int64_t)(x * 0x2545F4914F6CDD1DULL);
}

int int64_cmp(const void* a, const void* b) {
    int64_t x = *(const int64_t*)a;
    int64_t y = *(const int64_t*)b;
    if (x < y) return -1;
    if (x > y) return  1;
    return 0;
}

int int64_cmp_ptr(const void* a, const void* b) {
    int64_t x = *(const int64_t*)a;
    int64_t y = *(const int64_t*)b;
    if (x < y) return -1;
    if (x > y) return  1;
    return 0;
}

/* In-memory quicksort on an array of int64 values. */
static void swap64(int64_t* a, int64_t* b) {
    int64_t t = *a; *a = *b; *b = t;
}

static long partition64(int64_t* a, long lo, long hi) {
    int64_t pivot = a[hi];
    long i = lo - 1;
    for (long j = lo; j < hi; j++) {
        if (a[j] <= pivot) {
            i++;
            swap64(&a[i], &a[j]);
        }
    }
    swap64(&a[i+1], &a[hi]);
    return i + 1;
}

static void qsort64_rec(int64_t* a, long lo, long hi) {
    if (lo >= hi) return;
    /* Insertion sort for small sub-arrays. */
    if (hi - lo < 16) {
        for (long i = lo + 1; i <= hi; i++) {
            int64_t v = a[i];
            long j = i - 1;
            while (j >= lo && a[j] > v) { a[j+1] = a[j]; j--; }
            a[j+1] = v;
        }
        return;
    }
    long p = partition64(a, lo, hi);
    qsort64_rec(a, lo, p - 1);
    qsort64_rec(a, p + 1, hi);
}

void qsort_int64(int64_t* buf, long n) {
    if (n <= 1) return;
    qsort64_rec(buf, 0, n - 1);
}

void isort(int64_t* buf, long n) {
    for (long i = 1; i < n; i++) {
        int64_t v = buf[i];
        long j = i - 1;
        while (j >= 0 && buf[j] > v) { buf[j+1] = buf[j]; j--; }
        buf[j+1] = v;
    }
}

/* Fisher-Yates partial shuffle to pick k distinct indices. */
void sample_indices(long n, int k, long* out) {
    if (k > n) k = (int)n;
    /* Use a small reservoir: shuffle the first k of [0..n). */
    long* pool = (long*)malloc(sizeof(long) * n);
    for (long i = 0; i < n; i++) pool[i] = i;
    for (long i = 0; i < k; i++) {
        long j = i + (long)(utils_rand64() % (uint64_t)(n - i));
        long tmp = pool[i]; pool[i] = pool[j]; pool[j] = tmp;
        out[i] = pool[i];
    }
    free(pool);
}

/* Generate `n` random int64 values and write them as the contents of
 * the binary file `filename` (one int64 per 8 bytes, little-endian on
 * disk). */
void gen_random_file(const char* filename, long n) {
    DiskFile* df = disk_open(filename, "wb");
    if (!df) {
        fprintf(stderr, "Could not create %s\n", filename);
        exit(1);
    }
    long blocks = (n + INTS_PER_BLOCK - 1) / INTS_PER_BLOCK;
    long written = 0;
    for (long b = 0; b < blocks; b++) {
        int64_t tmp[INTS_PER_BLOCK];
        long cap = (b == blocks - 1) ? (n - written) : INTS_PER_BLOCK;
        for (long i = 0; i < cap; i++) {
            tmp[i] = utils_rand64();
        }
        /* Pad the last (possibly partial) block with INT64_MAX so that
         * the binary file is always a multiple of BLOCK_SIZE bytes. */
        for (long i = cap; i < INTS_PER_BLOCK; i++) tmp[i] = INT64_MAX;
        disk_write_block(df, b, tmp);
        written += cap;
    }
    disk_close(df);
}

/* Verify that the binary file is sorted. */
int verify_sorted(const char* filename, long n) {
    DiskFile* df = disk_open(filename, "rb");
    if (!df) {
        fprintf(stderr, "Could not open %s\n", filename);
        return 0;
    }
    long blocks = (n + INTS_PER_BLOCK - 1) / INTS_PER_BLOCK;
    int64_t prev = INT64_MIN;
    int64_t buf[INTS_PER_BLOCK];
    int ok = 1;
    for (long b = 0; b < blocks; b++) {
        disk_read_block(df, b, buf);
        long cap = (b == blocks - 1) ? (n - (b * INTS_PER_BLOCK)) : INTS_PER_BLOCK;
        for (long i = 0; i < cap; i++) {
            if (buf[i] < prev) {
                fprintf(stderr,
                        "Sort violation at position %ld: %ld < %ld\n",
                        b * INTS_PER_BLOCK + i, (long)buf[i], (long)prev);
                ok = 0;
                goto done;
            }
            prev = buf[i];
        }
    }
done:
    disk_close(df);
    return ok;
}

#include "mergesort.h"
#include "disk.h"
#include "utils.h"

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/stat.h>

/* ------------------------------------------------------------------ */
/* Small helpers                                                       */
/* ------------------------------------------------------------------ */

/* Make sure the directory used for temporary run files exists. */
static void ensure_tmpdir(const char* dir) {
    struct stat st;
    if (stat(dir, &st) == 0) return;
    /* Create the directory recursively (a few levels deep). */
    char tmp[512];
    strncpy(tmp, dir, sizeof(tmp) - 1);
    tmp[sizeof(tmp) - 1] = 0;
    for (char* p = tmp + 1; *p; p++) {
        if (*p == '/') {
            *p = 0;
            mkdir(tmp, 0700);
            *p = '/';
        }
    }
    mkdir(tmp, 0700);
}

/* Build a path of the form "<dir>/run_<pass>_<idx>.bin". */
static void make_run_path(char* out, size_t outsz,
                          const char* dir, int pass, int idx) {
    snprintf(out, outsz, "%s/run_p%d_%d.bin", dir, pass, idx);
}

/* Delete every file in `paths`, an array of `count` C-strings. */
static void cleanup_files(char** paths, int count) {
    for (int i = 0; i < count; i++) {
        if (paths[i]) remove(paths[i]);
    }
}

/* ------------------------------------------------------------------ */
/* Phase 1: build initial runs of size M                               */
/* ------------------------------------------------------------------ */

static int build_initial_runs(const char* input_file, const char* tmpdir,
                              int* out_num_runs, char*** out_paths,
                              long n, long M_elements) {
    ensure_tmpdir(tmpdir);

    int num_runs = (int)((n + M_elements - 1) / M_elements);
    char** paths = (char**)calloc((size_t)num_runs, sizeof(char*));
    for (int i = 0; i < num_runs; i++) {
        paths[i] = (char*)malloc(256);
        make_run_path(paths[i], 256, tmpdir, 0, i);
    }

    /* Buffer big enough to hold an entire run in memory. */
    int64_t* runbuf = (int64_t*)malloc(sizeof(int64_t) * M_elements);
    if (!runbuf) {
        fprintf(stderr, "Out of memory allocating initial run buffer\n");
        return -1;
    }

    DiskFile* in = disk_open(input_file, "rb");
    if (!in) {
        fprintf(stderr, "Cannot open input file %s\n", input_file);
        free(runbuf);
        return -1;
    }

    long total_blocks = (n + INTS_PER_BLOCK - 1) / INTS_PER_BLOCK;
    long read_blocks = 0;

    for (int r = 0; r < num_runs; r++) {
        /* Reset the in-memory buffer for this run. */
        long run_lo = (long)r * M_elements;
        long run_hi = run_lo + M_elements;
        if (run_hi > n) run_hi = n;
        long run_len = run_hi - run_lo;

        /* Read the run into memory, going through block-sized chunks. */
        long filled = 0;
        long first_block = run_lo / INTS_PER_BLOCK;
        long last_block  = (run_hi - 1) / INTS_PER_BLOCK;
        for (long b = first_block; b <= last_block; b++) {
            int64_t tmp[INTS_PER_BLOCK];
            disk_read_block(in, b, tmp);
            read_blocks++;
            long block_lo = b * INTS_PER_BLOCK;
            long copy_lo  = (block_lo > run_lo) ? block_lo : run_lo;
            long copy_hi  = (block_lo + INTS_PER_BLOCK < run_hi)
                            ? (block_lo + INTS_PER_BLOCK) : run_hi;
            long copy_len = copy_hi - copy_lo;
            memcpy(runbuf + filled, tmp + (copy_lo - block_lo),
                   sizeof(int64_t) * copy_len);
            filled += copy_len;
        }

        /* In-memory sort. */
        qsort_int64(runbuf, run_len);

        /* Write the sorted run to its own file. */
        DiskFile* df = disk_open(paths[r], "wb");
        if (!df) {
            fprintf(stderr, "Cannot create run file %s\n", paths[r]);
            return -1;
        }
        long written = 0;
        while (written < run_len) {
            int64_t tmp[INTS_PER_BLOCK];
            long chunk = (run_len - written < INTS_PER_BLOCK)
                         ? (run_len - written) : INTS_PER_BLOCK;
            memcpy(tmp, runbuf + written, sizeof(int64_t) * chunk);
            /* Pad with INT64_MAX so the file size is a multiple of
             * BLOCK_SIZE; later we will only read up to `run_len`. */
            for (long i = chunk; i < INTS_PER_BLOCK; i++) tmp[i] = INT64_MAX;
            long block_idx = written / INTS_PER_BLOCK;
            disk_write_block(df, block_idx, tmp);
            written += chunk;
        }
        disk_close(df);
    }
    disk_close(in);
    free(runbuf);

    *out_num_runs = num_runs;
    *out_paths    = paths;
    (void)total_blocks; (void)read_blocks;
    return 0;
}

/* ------------------------------------------------------------------ */
/* Phase 2: a-way merge of a list of runs                              */
/* ------------------------------------------------------------------ */

typedef struct {
    DiskFile* file;       /* backing file for the stream                */
    int64_t*  buffer;     /* INTS_PER_BLOCK-sized block buffer          */
    long      total_elems;/* number of valid elements in the run         */
    long      read_elems; /* elements already pulled from the run        */
    int       buf_pos;    /* next index in buffer                        */
    int       buf_size;   /* valid elements currently in buffer          */
    int       exhausted;  /* 1 if no more elements remain                */
} Stream;

static void stream_open(Stream* s, const char* path, long total_elems) {
    s->file        = disk_open(path, "rb");
    s->buffer      = (int64_t*)malloc(sizeof(int64_t) * INTS_PER_BLOCK);
    s->total_elems = total_elems;
    s->read_elems  = 0;
    s->buf_pos     = 0;
    s->buf_size    = 0;
    s->exhausted   = (total_elems == 0);
}

static void stream_close(Stream* s) {
    if (s->file) disk_close(s->file);
    free(s->buffer);
    s->file = NULL;
}

/* Refill `s->buffer` with the next block of the run. Returns 1 if any
 * valid element was loaded, 0 if the stream is now exhausted. */
static int stream_refill(Stream* s) {
    if (s->read_elems >= s->total_elems) {
        s->exhausted = 1;
        s->buf_size  = 0;
        s->buf_pos   = 0;
        return 0;
    }
    long remaining = s->total_elems - s->read_elems;
    long chunk = (remaining < INTS_PER_BLOCK) ? remaining : INTS_PER_BLOCK;
    long block_idx = s->read_elems / INTS_PER_BLOCK;
    int64_t tmp[INTS_PER_BLOCK];
    disk_read_block(s->file, block_idx, tmp);
    memcpy(s->buffer, tmp, sizeof(int64_t) * INTS_PER_BLOCK);
    s->read_elems += chunk;
    s->buf_pos     = 0;
    s->buf_size    = (int)chunk;
    return 1;
}

/* ------------------------------------------------------------------ */
/* Min-heap used for the a-way merge.                                  */
/* ------------------------------------------------------------------ */

typedef struct {
    int64_t key;
    int     stream;     /* index of the stream this element came from   */
} HeapEntry;

static void heap_swap(HeapEntry* a, HeapEntry* b) {
    HeapEntry t = *a; *a = *b; *b = t;
}

static void heap_sift_up(HeapEntry* h, int i) {
    while (i > 0) {
        int p = (i - 1) / 2;
        if (h[p].key <= h[i].key) break;
        heap_swap(&h[p], &h[i]);
        i = p;
    }
}

static void heap_sift_down(HeapEntry* h, int n, int i) {
    for (;;) {
        int l = 2*i + 1, r = 2*i + 2, m = i;
        if (l < n && h[l].key < h[m].key) m = l;
        if (r < n && h[r].key < h[m].key) m = r;
        if (m == i) break;
        heap_swap(&h[m], &h[i]);
        i = m;
    }
}

/* ------------------------------------------------------------------ */
/* Merge `num_inputs` sorted runs into a single run written to         */
/* `output_path`. The total output length is `total_elems`.            */
/* ------------------------------------------------------------------ */

static void merge_k_runs(char** input_paths, const long* input_lens,
                         int num_inputs, const char* output_path,
                         long total_elems) {
    Stream* streams = (Stream*)calloc((size_t)num_inputs, sizeof(Stream));
    HeapEntry* heap = (HeapEntry*)malloc(sizeof(HeapEntry) * num_inputs);
    int heap_size = 0;

    /* Open every input stream and prime its first block. */
    for (int i = 0; i < num_inputs; i++) {
        stream_open(&streams[i], input_paths[i], input_lens[i]);
        if (stream_refill(&streams[i])) {
            heap[heap_size].key    = streams[i].buffer[0];
            heap[heap_size].stream = i;
            heap_size++;
        }
    }
    /* Build the heap. */
    for (int i = heap_size / 2 - 1; i >= 0; i--) {
        heap_sift_down(heap, heap_size, i);
    }

    DiskFile* out = disk_open(output_path, "wb");
    int64_t out_buf[INTS_PER_BLOCK];
    long out_pos = 0;        /* next slot to write in out_buf            */
    long out_written = 0;    /* total elements written so far            */

    while (heap_size > 0) {
        HeapEntry top = heap[0];
        out_buf[out_pos++] = top.key;
        out_written++;

        if (out_pos == INTS_PER_BLOCK) {
            long block_idx = (out_written - INTS_PER_BLOCK) / INTS_PER_BLOCK;
            disk_write_block(out, block_idx, out_buf);
            out_pos = 0;
        }

        int s_idx = top.stream;
        Stream* s = &streams[s_idx];
        s->buf_pos++;
        if (s->buf_pos >= s->buf_size) {
            if (!stream_refill(s)) {
                /* Stream is done: remove it from the heap. */
                heap[0] = heap[heap_size - 1];
                heap_size--;
                heap_sift_down(heap, heap_size, 0);
                continue;
            }
        }
        heap[0].key = s->buffer[s->buf_pos];
        heap_sift_down(heap, heap_size, 0);
    }

    /* Flush the final (possibly partial) output block. We must write a
     * full block to disk to keep the access granularity at B bytes, so
     * we pad the unused slots with INT64_MAX. */
    if (out_pos > 0) {
        for (long i = out_pos; i < INTS_PER_BLOCK; i++) out_buf[i] = INT64_MAX;
        long block_idx = (out_written - 1) / INTS_PER_BLOCK;
        disk_write_block(out, block_idx, out_buf);
    }
    disk_close(out);
    for (int i = 0; i < num_inputs; i++) stream_close(&streams[i]);
    free(streams);
    free(heap);

    (void)total_elems; /* total_elems is implicit in the sum of inputs. */
}

/* ------------------------------------------------------------------ */
/* Top-level driver                                                    */
/* ------------------------------------------------------------------ */

int external_mergesort(const char* input_file,
                       const char* output_file,
                       long n, long M_elements, int arity) {
    if (n <= 0) return 0;
    if (arity < 2) arity = 2;

    const char* tmpdir = "data/runs";
    char** cur_paths = NULL;
    long*  cur_lens  = NULL;
    int    cur_runs  = 0;

    /* Phase 1 */
    if (build_initial_runs(input_file, tmpdir, &cur_runs, &cur_paths, n,
                           M_elements) != 0) {
        return -1;
    }
    cur_lens = (long*)malloc(sizeof(long) * cur_runs);
    for (int i = 0; i < cur_runs; i++) {
        long lo = (long)i * M_elements;
        long hi = lo + M_elements;
        if (hi > n) hi = n;
        cur_lens[i] = hi - lo;
    }

    /* Phase 2: iterative a-way merging */
    int pass = 1;
    while (cur_runs > 1) {
        int next_runs = (cur_runs + arity - 1) / arity;
        char** next_paths = (char**)calloc((size_t)next_runs, sizeof(char*));
        long*  next_lens  = (long*)calloc((size_t)next_runs, sizeof(long));

        for (int g = 0; g < next_runs; g++) {
            int start = g * arity;
            int end   = start + arity;
            if (end > cur_runs) end = cur_runs;
            int grp_sz = end - start;
            long total = 0;
            for (int i = start; i < end; i++) total += cur_lens[i];

            next_paths[g] = (char*)malloc(256);
            make_run_path(next_paths[g], 256, tmpdir, pass, g);
            merge_k_runs(&cur_paths[start], &cur_lens[start], grp_sz,
                         next_paths[g], total);
            next_lens[g] = total;
        }

        /* Drop the old run files, swap arrays, advance pass index. */
        cleanup_files(cur_paths, cur_runs);
        for (int i = 0; i < cur_runs; i++) free(cur_paths[i]);
        free(cur_paths);
        free(cur_lens);

        cur_paths = next_paths;
        cur_lens  = next_lens;
        cur_runs  = next_runs;
        pass++;
    }

    /* Move the final run to `output_file`. */
    if (cur_runs == 1) {
        remove(output_file);
        if (rename(cur_paths[0], output_file) != 0) {
            /* Fallback: copy manually in block-sized chunks. */
            DiskFile* in  = disk_open(cur_paths[0], "rb");
            DiskFile* out = disk_open(output_file, "wb");
            long blocks = disk_total_blocks(in);
            int64_t buf[INTS_PER_BLOCK];
            for (long b = 0; b < blocks; b++) {
                disk_read_block(in, b, buf);
                disk_write_block(out, b, buf);
            }
            disk_close(in);
            disk_close(out);
        }
    }
    cleanup_files(cur_paths, cur_runs);
    for (int i = 0; i < cur_runs; i++) free(cur_paths[i]);
    free(cur_paths);
    free(cur_lens);
    return 0;
}

int external_mergesort_measure(const char* input_file,
                               const char* output_file,
                               long n, long M_elements, int arity) {
    reset_counters();
    int rc = external_mergesort(input_file, output_file, n, M_elements, arity);
    return rc;
}

