```c
static int find_bucket(int64_t x, const int64_t* pivots, int arity) {
    int lo = 0, hi = arity - 2;  // search pivots[0..arity-2]
    while (lo <= hi) {
        int mid = (lo + hi) / 2;
        if (pivots[mid] <= x) {
            lo = mid + 1;
        } else {
            hi = mid - 1;
        }
    }
    // lo is the smallest index such that pivots[lo] > x, or arity-1 if x >= all pivots
    return lo;  // this gives bucket in [0, arity-1]
}
