#include "quicksort.h"
#include "disk.h"
#include "utils.h"

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/stat.h>

/* ------------------------------------------------------------------ */
/* Helpers                                                             */
/* ------------------------------------------------------------------ */

static void ensure_tmpdir(const char* dir) {
    struct stat st;
    if (stat(dir, &st) == 0) return;
    char tmp[512];
    strncpy(tmp, dir, sizeof(tmp) - 1);
    tmp[sizeof(tmp) - 1] = 0;
    for (char* p = tmp + 1; *p; p++) {
        if (*p == '/') {
            *p = 0;
            mkdir(tmp, 0700);
            *p = '/';
        }
    }
    mkdir(tmp, 0700);
}

/* Given a value `x` and the sorted pivot array `pivots[0..arity-2]`,
 * return the index of the sub-array the value belongs to. The sub-
 * array indices are in [0, arity-1] with sub-array 0 containing all
 * values strictly less than `pivots[0]`, sub-array k (0 < k < a-1)
 * containing values in [pivots[k-1], pivots[k]) and sub-array a-1
 * containing values >= pivots[a-2]. */
static int find_bucket(int64_t x, const int64_t* pivots, int arity) {
    int lo = 0, hi = arity - 2;
    while (lo <= hi) {
        int mid = (lo + hi) / 2;
        if (pivots[mid] <= x) lo = mid + 1;
        else                  hi = mid - 1;
    }
    return lo;
}

/* ------------------------------------------------------------------ */
/* In-memory sort: read whole input, quicksort it, write whole output */
/* ------------------------------------------------------------------ */

static int in_memory_sort(const char* input_file, const char* output_file,
                          long n) {
    if (n <= 0) {
        DiskFile* out = disk_open(output_file, "wb");
        if (out) disk_close(out);
        return 0;
    }
    DiskFile* in = disk_open(input_file, "rb");
    if (!in) return -1;

    int64_t* buf = (int64_t*)malloc(sizeof(int64_t) * (size_t)n);
    if (!buf) { disk_close(in); return -1; }

    long blocks = (n + INTS_PER_BLOCK - 1) / INTS_PER_BLOCK;
    for (long b = 0; b < blocks; b++) {
        int64_t tmp[INTS_PER_BLOCK];
        disk_read_block(in, b, tmp);
        long cap = (b == blocks - 1)
                   ? (n - b * INTS_PER_BLOCK) : INTS_PER_BLOCK;
        memcpy(buf + b * INTS_PER_BLOCK, tmp, sizeof(int64_t) * (size_t)cap);
    }
    disk_close(in);

    qsort_int64(buf, n);

    DiskFile* out = disk_open(output_file, "wb");
    if (!out) { free(buf); return -1; }
    long written = 0;
    while (written < n) {
        int64_t tmp[INTS_PER_BLOCK];
        long chunk = (n - written < INTS_PER_BLOCK)
                     ? (n - written) : INTS_PER_BLOCK;
        memcpy(tmp, buf + written, sizeof(int64_t) * (size_t)chunk);
        for (long i = chunk; i < INTS_PER_BLOCK; i++) tmp[i] = INT64_MAX;
        disk_write_block(out, written / INTS_PER_BLOCK, tmp);
        written += chunk;
    }
    disk_close(out);
    free(buf);
    return 0;
}

/* ------------------------------------------------------------------ */
/* Recursive external quicksort                                        */
/* ------------------------------------------------------------------ */

static int qsort_recursive(const char* input_file, const char* output_file,
                           long n, long M_elements, int arity,
                           const char* tmpdir, int depth, int idx) {
    /* Base case: the array fits in main memory. */
    if (n <= M_elements) {
        return in_memory_sort(input_file, output_file, n);
    }
    if (arity < 2) arity = 2;

    /* ---- 1. Read a random block and derive a-1 pivots. ---------- */
    DiskFile* in = disk_open(input_file, "rb");
    if (!in) return -1;
    long num_blocks = (n + INTS_PER_BLOCK - 1) / INTS_PER_BLOCK;
    long rand_block = (long)(utils_rand64() % (uint64_t)num_blocks);

    int64_t pivot_block[INTS_PER_BLOCK];
    disk_read_block(in, rand_block, pivot_block);
    /* The random block is now cached. We will need to rewind, so we
     * flush the cache (no-op because the buffer is still clean) and
     * re-read from the start. */

    long sample_pos[512];
    sample_indices(INTS_PER_BLOCK, arity - 1, sample_pos);

    int64_t pivots[512];
    for (int i = 0; i < arity - 1; i++) {
        pivots[i] = pivot_block[sample_pos[i]];
    }
    qsort_int64(pivots, arity - 1);

    /* ---- 2. Set up a output streams. --------------------------- */
    char (*sub_paths)[256] = (char (*)[256])malloc(sizeof(char[256]) * arity);
    long* sub_sizes = (long*)calloc((size_t)arity, sizeof(long));
    DiskFile** sub_files  = (DiskFile**)malloc(sizeof(DiskFile*) * arity);
    int64_t**  sub_bufs   = (int64_t**)malloc(sizeof(int64_t*) * arity);
    int*       sub_pos    = (int*)calloc((size_t)arity, sizeof(int));

    for (int i = 0; i < arity; i++) {
        snprintf(sub_paths[i], 256, "%s/p_d%d_i%d_s%d.bin",
                 tmpdir, depth, idx, i);
        sub_files[i] = disk_open(sub_paths[i], "wb");
        if (!sub_files[i]) {
            fprintf(stderr, "Cannot create sub-file %s\n", sub_paths[i]);
            return -1;
        }
        sub_bufs[i] = (int64_t*)malloc(sizeof(int64_t) * INTS_PER_BLOCK);
    }

    /* ---- 3. Scan the input sequentially and route each element. */
    disk_invalidate_cache(in);
    int64_t in_buf[INTS_PER_BLOCK];
    for (long b = 0; b < num_blocks; b++) {
        disk_read_block(in, b, in_buf);
        long cap = (b == num_blocks - 1)
                   ? (n - b * INTS_PER_BLOCK) : INTS_PER_BLOCK;
        for (long i = 0; i < cap; i++) {
            int64_t v = in_buf[i];
            int k = find_bucket(v, pivots, arity);
            sub_bufs[k][sub_pos[k]++] = v;
            sub_sizes[k]++;
            if (sub_pos[k] == INTS_PER_BLOCK) {
                long block_idx = (sub_sizes[k] - 1) / INTS_PER_BLOCK;
                disk_write_block(sub_files[k], block_idx, sub_bufs[k]);
                sub_pos[k] = 0;
            }
        }
    }
    disk_close(in);

    /* Flush partially filled output buffers, padding with INT64_MAX
     * so the file size is a multiple of BLOCK_SIZE bytes. */
    for (int i = 0; i < arity; i++) {
        if (sub_pos[i] > 0) {
            for (long j = sub_pos[i]; j < INTS_PER_BLOCK; j++) {
                sub_bufs[i][j] = INT64_MAX;
            }
            long block_idx = sub_sizes[i] / INTS_PER_BLOCK;
            disk_write_block(sub_files[i], block_idx, sub_bufs[i]);
        }
        disk_close(sub_files[i]);
        free(sub_bufs[i]);
    }

    /* ---- 4. Recursively sort every non-empty sub-file. -------- */
    char (*sorted_paths)[256] =
        (char (*)[256])malloc(sizeof(char[256]) * arity);
    long* sorted_sizes = (long*)calloc((size_t)arity, sizeof(long));

    for (int i = 0; i < arity; i++) {
        if (sub_sizes[i] == 0) continue;
        snprintf(sorted_paths[i], 256, "%s/s_d%d_i%d_s%d.bin",
                 tmpdir, depth, idx, i);
        qsort_recursive(sub_paths[i], sorted_paths[i], sub_sizes[i],
                        M_elements, arity, tmpdir, depth + 1, i);
        sorted_sizes[i] = sub_sizes[i];
    }

    /* ---- 5. Concatenate the sorted sub-files into output_file. - */
    remove(output_file);
    DiskFile* out = disk_open(output_file, "wb");
    if (!out) {
        fprintf(stderr, "Cannot create output file %s\n", output_file);
        return -1;
    }
    long next_block = 0;
    for (int i = 0; i < arity; i++) {
        if (sorted_sizes[i] == 0) continue;
        DiskFile* src = disk_open(sorted_paths[i], "rb");
        if (!src) {
            disk_close(out);
            return -1;
        }
        long sblocks = disk_total_blocks(src);
        int64_t tmp[INTS_PER_BLOCK];
        for (long b = 0; b < sblocks; b++) {
            disk_read_block(src, b, tmp);
            disk_write_block(out, next_block++, tmp);
        }
        disk_close(src);
    }
    disk_close(out);

    /* ---- 6. Cleanup. ------------------------------------------- */
    for (int i = 0; i < arity; i++) {
        remove(sub_paths[i]);
        if (sorted_sizes[i] > 0) remove(sorted_paths[i]);
    }
    free(sub_paths);
    free(sub_bufs);
    free(sub_files);
    free(sub_sizes);
    free(sub_pos);
    free(sorted_paths);
    free(sorted_sizes);

    return 0;
}

/* ------------------------------------------------------------------ */
/* Public entry points                                                 */
/* ------------------------------------------------------------------ */

int external_quicksort(const char* input_file,
                       const char* output_file,
                       long n, long M_elements, int arity) {
    if (n <= 0) return 0;
    ensure_tmpdir("data/qruns");
    return qsort_recursive(input_file, output_file, n, M_elements, arity,
                           "data/qruns", 0, 0);
}

int external_quicksort_measure(const char* input_file,
                               const char* output_file,
                               long n, long M_elements, int arity) {
    reset_counters();
    int rc = external_quicksort(input_file, output_file, n, M_elements, arity);
    return rc;
}

