#include "experiment.h"
#include "disk.h"
#include "utils.h"
#include "mergesort.h"
#include "quicksort.h"

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <sys/time.h>

/* ------------------------------------------------------------------ */
/* Timing helpers                                                      */
/* ------------------------------------------------------------------ */

static double now_seconds(void) {
    struct timespec ts;
    clock_gettime(CLOCK_MONOTONIC, &ts);
    return (double)ts.tv_sec + (double)ts.tv_nsec * 1e-9;
}

/* ------------------------------------------------------------------ */
/* Measure sort runs                                                   */
/* ------------------------------------------------------------------ */

int experiment_run_mergesort(const char* input_file, const char* output_file,
                             long n, int arity, SortResult* result) {
    reset_counters();
    double t0 = now_seconds();
    int rc = external_mergesort(input_file, output_file, n, M_ELEMENTS, arity);
    double t1 = now_seconds();
    if (rc != 0) return rc;
    result->seconds       = t1 - t0;
    result->disk_reads    = g_disk_reads;
    result->disk_writes   = g_disk_writes;
    result->disk_accesses = g_disk_reads + g_disk_writes;
    result->arity         = arity;
    return 0;
}

int experiment_run_quicksort(const char* input_file, const char* output_file,
                             long n, int arity, SortResult* result) {
    reset_counters();
    double t0 = now_seconds();
    int rc = external_quicksort(input_file, output_file, n, M_ELEMENTS, arity);
    double t1 = now_seconds();
    if (rc != 0) return rc;
    result->seconds       = t1 - t0;
    result->disk_reads    = g_disk_reads;
    result->disk_writes   = g_disk_writes;
    result->disk_accesses = g_disk_reads + g_disk_writes;
    result->arity         = arity;
    return 0;
}

/* ------------------------------------------------------------------ */
/* Best-arity search                                                   */
/* ------------------------------------------------------------------ */

/* Cache of measured disk-access counts keyed by arity. */
typedef struct {
    int*  keys;
    long* ios;
    int   size;
    int   cap;
} IOsCache;

static void ios_cache_init(IOsCache* c) {
    c->size = 0; c->cap = 16;
    c->keys = (int*)malloc(sizeof(int) * c->cap);
    c->ios  = (long*)malloc(sizeof(long) * c->cap);
}
static void ios_cache_free(IOsCache* c) {
    free(c->keys); free(c->ios);
}
static long ios_cache_get(IOsCache* c, int key) {
    for (int i = 0; i < c->size; i++) {
        if (c->keys[i] == key) return c->ios[i];
    }
    return -1;
}
static void ios_cache_put(IOsCache* c, int key, long value) {
    for (int i = 0; i < c->size; i++) {
        if (c->keys[i] == key) { c->ios[i] = value; return; }
    }
    if (c->size == c->cap) {
        c->cap *= 2;
        c->keys = (int*)realloc(c->keys, sizeof(int) * c->cap);
        c->ios  = (long*)realloc(c->ios, sizeof(long) * c->cap);
    }
    c->keys[c->size] = key;
    c->ios[c->size]  = value;
    c->size++;
}

/* Measure mergesort I/Os on `seq_file` with the given arity. */
static long measure_mergesort_ios(const char* seq_file, long n, int arity) {
    static int counter = 0;
    char out_file[256];
    snprintf(out_file, sizeof(out_file), "data/_arity_probe_%d.bin", counter++);
    SortResult res;
    experiment_run_mergesort(seq_file, out_file, n, arity, &res);
    remove(out_file);
    return res.disk_accesses;
}

int experiment_find_best_arity(const char* seq_16M_file) {
    long n = 16L * M_ELEMENTS;

    /* Memory feasibility check: (a+1) * B + small overhead <= M. */
    long max_a_by_mem = M_ELEMENTS / B_ELEMENTS;  /* very loose bound     */
    int hi = (int)(M_BYTES / B_BYTES) - 1;       /* (M/B) - 1            */
    if (hi > B_ELEMENTS) hi = B_ELEMENTS;        /* clamped to [2, b]    */

    IOsCache cache;
    ios_cache_init(&cache);

    /* Helper: measure, cache and print. */
    #define MEASURE(a) ({                                                \
        long _v = ios_cache_get(&cache, (a));                            \
        if (_v < 0) {                                                    \
            _v = measure_mergesort_ios(seq_16M_file, n, (a));            \
            ios_cache_put(&cache, (a), _v);                              \
        }                                                                \
        _v; })

    int lo = 2;
    /* Search using neighbour comparisons (binary search for argmin of
     * a monotone-decreasing sequence, robust to small noise). */
    while (lo < hi) {
        int mid = (lo + hi) / 2;
        long ios_mid   = MEASURE(mid);
        long ios_mid_1 = MEASURE(mid + 1);
        if (ios_mid > ios_mid_1) {
            lo = mid + 1;
        } else {
            hi = mid;
        }
    }
    int best = lo;
    long best_ios = MEASURE(best);

    /* Also check the immediate neighbour just in case the boundary
     * effect at the maximum arity would tip the balance. */
    if (best > 2) {
        long ios_prev = MEASURE(best - 1);
        if (ios_prev < best_ios) { best = best - 1; best_ios = ios_prev; }
    }
    if (best < hi) {
        long ios_next = MEASURE(best + 1);
        if (ios_next < best_ios) { best = best + 1; best_ios = ios_next; }
    }

    fprintf(stderr,
            "[best-arity] a=%d  I/Os=%ld  (memory-feasible max a=%d)\n",
            best, best_ios, max_a_by_mem);
    ios_cache_free(&cache);
    #undef MEASURE
    return best;
}

/* ------------------------------------------------------------------ */
/* Full experiment                                                      */
/* ------------------------------------------------------------------ */

static long multiple_to_n(int mult) {
    return (long)mult * M_ELEMENTS;
}

static const char* seq_path(int mult, int run) {
    static char buf[256];
    snprintf(buf, sizeof(buf), "data/seq_%dxM_run%d.bin", mult, run);
    return buf;
}

int experiment_run_all(const char* csv_path) {
    const int multiples[] = N_MULTIPLES;
    const int num_mults  = (int)(sizeof(multiples) / sizeof(multiples[0]));

    /* Ensure output directories exist. */
    mkdir("data",    0700);
    mkdir("results", 0700);

    /* Step 1: generate the 16M sequence used to find the best arity. */
    fprintf(stderr, "[step 1] Generating 16M sequence for arity search...\n");
    const char* seq16 = "data/seq_16xM_for_arity.bin";
    long n16 = multiple_to_n(16);
    gen_random_file(seq16, n16);

    /* Step 2: find the best arity. */
    fprintf(stderr, "[step 2] Searching best arity (binary search)...\n");
    int best_a = experiment_find_best_arity(seq16);
    fprintf(stderr, "[step 2] Best arity = %d\n", best_a);

    /* Step 3: generate sequences for all sizes. */
    fprintf(stderr, "[step 3] Generating test sequences...\n");
    for (int m = 0; m < num_mults; m++) {
        long n = multiple_to_n(multiples[m]);
        for (int r = 0; r < RUNS_PER_N; r++) {
            const char* p = seq_path(multiples[m], r);
            fprintf(stderr, "  generating %s (N=%ld ints)...\n", p, n);
            gen_random_file(p, n);
        }
    }

    /* Step 4: run both algorithms on every sequence. */
    FILE* csv = fopen(csv_path, "w");
    if (!csv) {
        fprintf(stderr, "Cannot open CSV file %s\n", csv_path);
        return -1;
    }
    fprintf(csv,
            "algorithm,multiple_of_M,n_elements,arity,run,"
            "seconds,disk_reads,disk_writes,disk_accesses\n");

    for (int m = 0; m < num_mults; m++) {
        long n = multiple_to_n(multiples[m]);
        for (int r = 0; r < RUNS_PER_N; r++) {
            const char* in = seq_path(multiples[m], r);
            char sorted[256];
            snprintf(sorted, sizeof(sorted), "data/_sorted_%dxM_r%d.bin",
                     multiples[m], r);

            SortResult res;

            fprintf(stderr,
                    "  [mergesort] mult=%dxM run=%d n=%ld a=%d ...\n",
                    multiples[m], r, n, best_a);
            if (experiment_run_mergesort(in, sorted, n, best_a, &res) != 0) {
                fclose(csv);
                return -1;
            }
            fprintf(csv,
                    "mergesort,%d,%ld,%d,%d,%.6f,%ld,%ld,%ld\n",
                    multiples[m], n, best_a, r,
                    res.seconds, res.disk_reads, res.disk_writes,
                    res.disk_accesses);

            fprintf(stderr,
                    "  [quicksort] mult=%dxM run=%d n=%ld a=%d ...\n",
                    multiples[m], r, n, best_a);
            if (experiment_run_quicksort(in, sorted, n, best_a, &res) != 0) {
                fclose(csv);
                return -1;
            }
            fprintf(csv,
                    "quicksort,%d,%ld,%d,%d,%.6f,%ld,%ld,%ld\n",
                    multiples[m], n, best_a, r,
                    res.seconds, res.disk_reads, res.disk_writes,
                    res.disk_accesses);

            remove(sorted);
        }
    }
    fclose(csv);
    fprintf(stderr, "[done] CSV written to %s\n", csv_path);
    return 0;
}

/*
 * main.c - Entry point for the CC4102 Tarea 1 experiment.
 *
 * Usage:
 *     ./tarea1                       Run the full experiment.
 *     ./tarea1 gen <path> <n>        Generate a random binary file.
 *     ./tarea1 verify <path> <n>     Verify that the file is sorted.
 *     ./tarea1 bench                 Alias for the full experiment.
 *     ./tarea1 help                  Print usage information.
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/stat.h>

#include "disk.h"
#include "utils.h"
#include "experiment.h"

static void ensure_dirs(void) {
    mkdir("data",    0700);
    mkdir("results", 0700);
}

static int do_gen(int argc, char** argv) {
    if (argc < 2) {
        fprintf(stderr, "Usage: %s gen <path> <n> [seed]\n", argv[0]);
        return 1;
    }
    const char* path = argv[1];
    long n = atol(argv[2]);
    unsigned int seed = (argc >= 4) ? (unsigned)atoi(argv[3])
                                    : (unsigned)time(NULL);
    utils_seed(seed);
    gen_random_file(path, n);
    printf("Generated %s with %ld random int64 (seed=%u)\n", path, n, seed);
    return 0;
}

static int do_verify(int argc, char** argv) {
    if (argc < 2) {
        fprintf(stderr, "Usage: %s verify <path> <n>\n", argv[0]);
        return 1;
    }
    const char* path = argv[1];
    long n = atol(argv[2]);
    int ok = verify_sorted(path, n);
    printf("%s sorted=%s\n", path, ok ? "YES" : "NO");
    return ok ? 0 : 1;
}

static int do_bench(int argc, char** argv) {
    (void)argc; (void)argv;
    ensure_dirs();
    const char* csv = "results/summary.csv";
    return experiment_run_all(csv);
}

static void print_help(char* prog) {
    printf("CC4102 - Tarea 1: Mergesort externo v/s Quicksort externo\n");
    printf("\nUsage:\n");
    printf("  %s                       Run the full experiment (default).\n", prog);
    printf("  %s bench                 Same as above.\n", prog);
    printf("  %s gen <path> <n> [seed] Generate a binary file with n random int64.\n", prog);
    printf("  %s verify <path> <n>     Verify that a file contains a sorted array.\n", prog);
    printf("  %s help                  Print this message.\n", prog);
    printf("\nDefault benchmark output: results/summary.csv\n");
}

int main(int argc, char** argv) {
    ensure_dirs();
    if (argc <= 1) return do_bench(argc, argv);
    if (strcmp(argv[1], "help") == 0 || strcmp(argv[1], "-h") == 0) {
        print_help(argv[0]); return 0;
    }
    if (strcmp(argv[1], "bench") == 0) return do_bench(argc - 1, argv + 1);
    if (strcmp(argv[1], "gen")    == 0) return do_gen(argc - 1, argv + 1);
    if (strcmp(argv[1], "verify") == 0) return do_verify(argc - 1, argv + 1);
    fprintf(stderr, "Unknown command: %s\n", argv[1]);
    print_help(argv[0]);
    return 1;
}

