     * padded with INT64_MAX. We must therefore read only `sorted_sizes[i]`
     * elements from each sub-file and stream them into a fresh output
     * buffer, padding only the very last block of the output. */
    int64_t out_buf[INTS_PER_BLOCK];
    long out_pos  = 0;
    long blocks_written = 0;
    for (int i = 0; i < arity; i++) {
        if (sorted_sizes[i] == 0) continue;
