        int64_t tmp[INTS_PER_BLOCK];
        for (long b = 0; b < sblocks; b++) {
            disk_read_block(src, b, tmp);
            long valid = INTS_PER_BLOCK;
            if (copied + valid > sorted_sizes[i]) {
                valid = sorted_sizes[i] - copied;
            }
            for (long j = 0; j < valid; j++) {
                out_buf[out_pos++] = tmp[j];
                if (out_pos == INTS_PER_BLOCK) {
                    disk_write_block(out, blocks_written++, out_buf);
                    out_pos = 0;
                }
            }
            copied += valid;
        }
        disk_close(src);
    }
    if (out_pos > 0) {
        for (long j = out_pos; j < INTS_PER_BLOCK; j++) {
            out_buf[j] = INT64_MAX;
        }
