int experiment_find_best_arity(const char* seq_16M_file) {
    long n = 16L * M_ELEMENTS;

    /* Memory feasibility check: (a+1) * B + small overhead <= M. */
    long max_a_by_mem = M_ELEMENTS / B_ELEMENTS;  /* very loose bound     */
    int hi = (int)(M_BYTES / B_BYTES) - 1;       /* (M/B) - 1            */
    if (hi > B_ELEMENTS) hi = B_ELEMENTS;        /* clamped to [2, b]    */

    IOsCache cache;
    ios_cache_init(&cache);

    /* Helper: measure, cache and print. */
    #define MEASURE(a) ({                                                \
        long _v = ios_cache_get(&cache, (a));                            \
        if (_v < 0) {                                                    \
            _v = measure_mergesort_ios(seq_16M_file, n, (a));            \
            ios_cache_put(&cache, (a), _v);                              \
        }                                                                \
        _v; })

    /* External Mergesort's I/O cost is monotonically non-increasing in
     * the arity (more arity = fewer merge passes).  We therefore look
     * for the smallest arity a* in [2, b] such that the cost equals
     * the cost at the upper end of the range, which is the minimum.
     * The lookup is done with a binary search: a candidate `mid` is in
     * the optimal region iff f(mid) <= f(hi). */
    long ios_hi = MEASURE(hi);
    int lo = 2;
    while (lo < hi) {
        int mid = (lo + hi) / 2;
        long ios_mid = MEASURE(mid);
        if (ios_mid <= ios_hi) {
            hi = mid;
        } else {
            lo = mid + 1;
        }
    }
    int best = lo;
    long best_ios = MEASURE(best);

    /* Sanity check: probe the immediate neighbours in case the cost
     * function is not strictly monotone due to cache effects. */
    if (best > 2) {
        long ios_prev = MEASURE(best - 1);
        if (ios_prev < best_ios) { best = best - 1; best_ios = ios_prev; }
    }
    if (best < B_ELEMENTS) {
        long ios_next = MEASURE(best + 1);
        if (ios_next < best_ios) { best = best + 1; best_ios = ios_next; }
    }

    fprintf(stderr,
            "[best-arity] a=%d  I/Os=%ld  (memory-feasible max a=%ld)\n",
            best, best_ios, max_a_by_mem);
    ios_cache_free(&cache);
    #undef MEASURE
    return best;
}

