#include "mergesort.h"
#include "quicksort.h"

// Replicate the binary search logic from experiment.c with smaller b
typedef struct {
    int*  keys;
    long* ios;
    int   size;
    int   cap;
} IOsCache;

static void ios_cache_init(IOsCache* c) {
    c->size = 0; c->cap = 16;
    c->keys = (int*)malloc(sizeof(int) * c->cap);
    c->ios  = (long*)malloc(sizeof(long) * c->cap);
}
static void ios_cache_free(IOsCache* c) {
    free(c->keys); free(c->ios);
}
static long ios_cache_get(IOsCache* c, int key) {
    for (int i = 0; i < c->size; i++) if (c->keys[i] == key) return c->ios[i];
    return -1;
}
static void ios_cache_put(IOsCache* c, int key, long value) {
    for (int i = 0; i < c->size; i++) {
        if (c->keys[i] == key) { c->ios[i] = value; return; }
    }
    if (c->size == c->cap) {
        c->cap *= 2;
        c->keys = (int*)realloc(c->keys, sizeof(int) * c->cap);
        c->ios  = (long*)realloc(c->ios, sizeof(long) * c->cap);
    }
    c->keys[c->size] = key; c->ios[c->size] = value; c->size++;
}

static long measure(int arity, const char* seq, long n, long M) {
    reset_counters();
    external_mergesort(seq, "data/_out.bin", n, M, arity);
    return total_disk_accesses();
}

int main() {
    mkdir("data", 0700);
    utils_seed(42);

    long n = 16 * 4096;
    long M = 4096;
    int b = 32;

    gen_random_file("data/seq16.bin", n);

    IOsCache cache;
    ios_cache_init(&cache);

    #define MEASURE(a) ({ \
        long _v = ios_cache_get(&cache, (a)); \
        if (_v < 0) { _v = measure((a), "data/seq16.bin", n, M); ios_cache_put(&cache, (a), _v); } \
        _v; })

    int hi = b;
    long ios_hi = MEASURE(hi);
    int lo = 2;
    while (lo < hi) {
        int mid = (lo + hi) / 2;
        long ios_mid = MEASURE(mid);
        if (ios_mid <= ios_hi) hi = mid;
        else lo = mid + 1;
    }
    int best = lo;
    long best_ios = MEASURE(best);
    if (best > 2) {
        long ios_prev = MEASURE(best - 1);
        if (ios_prev < best_ios) { best = best - 1; best_ios = ios_prev; }
    }
    if (best < b) {
        long ios_next = MEASURE(best + 1);
        if (ios_next < best_ios) { best = best + 1; best_ios = ios_next; }
    }

    printf("Best arity: %d (I/Os=%ld)\n", best, best_ios);

    ios_cache_free(&cache);
    return 0;
}
EOF
